  () => ({
    mockSubscribeEvents: vi.fn().mockReturnValue('subscription-id'),
    mockPublishEvent: vi.fn(),
    mockTryKeepExistingSessionAsync: vi.fn().mockResolvedValue(true),
  }),
);

